sys_script_include.script:
/**
 * @class AppInstallAdjustSysDBobject
 * @description Script to change the Application Access of sys_db_objects
 * @since 32/02/2026
 * @date  32/02/2026
 * @version 1.0.0
 * @author Thomas Grensemann E-Mail: <thomas.grensemann@t-systems.com>
 *
 */

class AppInstallAdjustSysDBobject extends Record {
    /**
     * Change the TabelUtils access to public
     */
    adjustSysDBobject() {
        const query = 'name=sys_script_include';

        const params = {
            'table': 'sys_db_object',
            'query': query,
            'properties': JSON.stringify({
                create_access: true,
				update_access: true
            }),
            'stealth': true,
            'result': ''
        };

        const script = ScriptBuider.getScriptRecordUpdateByQuery();

        const result = new ScriptEvaluator().executScript('global', script, params);

		gs.debug('[AppInstallAdjustSysDBobject][adjustSysDBobject] result ==> ' + result);

        this.processResult(result,
            'x_984628_deploye_0',
            'Record update', 'Change Script Include access', 
			'sys_db_object',
            params);
    }
}
